import sys
def count_digits(n):
    return 1 if n==0 else len(str(n))
def is_armstrong(n):
    if n == 1:
        return False
    d=count_digits(n)
    return sum(int(ch)**d for ch in str(n))==n
def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    n=int(data[0])
    print('YES' if is_armstrong(n) else 'NO')
if __name__=='__main__':
    main()

